             // Create a stamp for the minimized window
             this._scaleManager.autoShrink(metaWindow, null);
             this._createAndPlaceClone(metaWindow, MIN_SCALE);
+
+            // Set visibility based on current workspace
+            const newState = this._scaleManager.getState(metaWindow);
+            if (newState && newState.container) {
