@@ -767,13 +777,25 @@ export default class MutterButterExtension extends Extension {

     _onWorkspaceChanged() {
         const activeWs = global.workspace_manager.get_active_workspace();
-        // Show/hide stamp containers based on whether their window is on
-        // the active workspace
         for (const [metaWindow, state] of this._scaleManager._states) {
             if (!state.container)
                 continue;
-            const onActiveWs = metaWindow.located_on_workspace(activeWs);
-            state.container.visible = onActiveWs;
+            // Check if the window is on the active workspace.
+            // located_on_workspace handles sticky windows (on all workspaces).
+            const visible = metaWindow.located_on_workspace(activeWs);
+            state.container.visible = visible;
+        }
+    }
+
+    /**
+     * Called when workspace switch animation starts.
+     * Hide all stamps during the transition so they don't float
+     * over the sliding workspace content.
+     */
+    _onWorkspaceSwitchStarted() {
+        for (const [_metaWindow, state] of this._scaleManager._states) {
+            if (state.container)
+                state.container.visible = false;
         }
     }

